input.old_string:
.sta-list-A-item .step {
  background: var(--color-dark);
  border-radius: 2pt;
  padding: 2pt 5pt;
  flex-shrink: 0;
  margin-top: 2pt;

input.new_string:
.sta-list-A-item .step {
  background: var(--color-accent);
  border-radius: 2pt;
  padding: 3pt 7pt;
  flex-shrink: 0;
  margin-top: 1pt;
  min-width: 22pt;
  text-align: center;

input.old_string:
.sta-list-A-item .step p {
  color: var(--color-white);
  font-family: var(--font-mono); font-size: 9pt; font-weight: 700;
  line-height: 1;
}

input.new_string:
.sta-list-A-item .step p {
  color: var(--color-white);
  font-family: var(--font-mono); font-size: 12pt; font-weight: 700;
  line-height: 1;
}
